#!/usr/bin/env node

import { mkdir, writeFile } from 'node:fs/promises';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

import { compileFromFile } from 'json-schema-to-typescript';

const scriptDir = path.dirname(fileURLToPath(import.meta.url));
const rootDir = path.resolve(scriptDir, '..', '..');
const schemaPath = path.resolve(rootDir, 'schema', 'mbt.evt.v1.schema.json');
const outputPath = path.resolve(rootDir, 'packages', 'protocol', 'src', 'types.ts');

const compiled = await compileFromFile(schemaPath, {
  bannerComment:
    '// This file is generated by tools/gen_types/generate-protocol-types.mjs.\n' +
    '// Do not edit directly.\n',
  format: false,
  style: {
    semi: true,
    singleQuote: true,
  },
  unknownAny: false,
});

const output = `${compiled.trim()}\n`;
await mkdir(path.dirname(outputPath), { recursive: true });
await writeFile(outputPath, output, 'utf8');

console.log(`Generated ${path.relative(rootDir, outputPath)}`);
